return missingTasks.map(task => {
  const row = task.json;

  // Parsing del ID por si los campos individuales vienen vacíos
  // Formato esperado en row.id: "CO_APP_4.4.8_2026-01-05"
  const rawId = (row.id || "").trim();
  const idParts = rawId.split('_');

  const pais = missingTasks.json.pais;
  const entorno = (row.entorno || idParts[1] || "").toUpperCase();
  const queryId = (row.query_id || idParts[2] || "").trim();

  // Buscamos la Query en el input (DataTable)
  const queryData = allQueries.find(q => 
    String(q.json.query_id) === queryId || 
    String(q.json.queryId) === queryId ||
    String(q.json.id) === queryId
  );

  // Buscamos la conexión técnica (Pais + Entorno)
  const dbConfig = masterDbList.find(d => 
    d.country === pais && 
    d.entorno === entorno
  );

  // Si no hay match, marcamos error para filtrar
  if (!queryData || !dbConfig) {
    return { json: { skip: true, reason: "No se encontró match técnico", query_id: queryId, pais, entorno } };
  }

  return {
    json: {
      ...row,
      pais: pais,
      entorno: entorno,
      query_id: queryId,

      // Credenciales para el subflujo
      server_host: dbConfig.server_host,
      port: dbConfig.port,
      user: dbConfig.user,
      password: dbConfig.password,
      database: dbConfig.db,
      channelId: dbConfig.channelId,

      // Queries SQL
      revisionQuery: queryData.json.revision || queryData.json.revisionQuery,
      correctionQuery: queryData.json.correction || queryData.json.correctionQuery,

      type: executionType
    }
  };
}).filter(item => !item.json.skip); // Solo devolvemos lo que se puede ejecutar

