let executionType = 'Daily';
if ($("Weekly Trigger").isExecuted) {
  executionType = 'Weekly';
} else if ($("Monthly Trigger").isExecuted) {
  executionType = 'Monthly';
}

// 2. Traer fuentes de datos
const allQueries = $input.all(); // Datos de la Data Table (revisionQuery, correctionQuery, etc.)
const missingTasks = $("Get pending").all(); // Datos del Sheets (lo que no se ejecutó)

// 3. Configuración Técnica de Servidores
const servers = {
  ARG_BLOCK: {
    server: "host.docker.internal",
    port: 11434,
    user: "usr_automatico",
    password: "1qaz2wsx3edc",
    db_info: [
      { db: "comfiar_ar", entorno: "APP", country: "AR", channelId: "19:KqPHeI2vg9nNHO2de_AHbQGLK2Xh8Ah8iODV2ttJh_k1@thread.tacv2" },
      { db: "comfiar_ar2", entorno: "APP2", country: "AR", channelId: "19:c46ff530842c4dabbd9500e73d0b894d@thread.tacv2" },
      { db: "comfiar_cines", entorno: "Cines", country: "AR", channelId: "19:b355b1cd3e6a4e4ea7ed85a227744184@thread.tacv2" },
      { db: "comfiar_pe", entorno: "APP", country: "PE", channelId: "19:d5b204e433134ff5b1f7a90e51d76982@thread.tacv2" },
      { db: "comfiar_cr", entorno: "APP", country: "CR", channelId: "19:a9547625aaea4e02ae5b373bdc352ae9@thread.tacv2" },
      { db: "comfiar_bo", entorno: "APP", country: "BO", channelId: "19:5e3bf46869f140a39d48f869795379c5@thread.tacv2" },
      { db: "comfiar_ec", entorno: "APP", country: "EC", channelId: "19:9b2cc90d29d3474bade3a60f407f56ca@thread.tacv2" }
    ]
  },
  COL_BLOCK: {
    server: "host.docker.internal",
    port: 11433,
    user: "usr_automatico",
    password: "1qaz2wsx3edc",
    db_info: [
      { db: "comfiar_co", entorno: "APP", country: "CO", channelId: "19:af378cf202564cfc87591f580cd70935@thread.tacv2" },
      { db: "comfiar_co2", entorno: "APP2", country: "CO", channelId: "19:d31a59baa80e47aba00f2944e684c4b3@thread.tacv2" },
      { db: "comfiar_co3", entorno: "APP3", country: "CO", channelId: "19:14b2fb9063904bccb047900af9ded2fe@thread.tacv2" }
    ]
  }
};

// 4. APLANAR CONFIGURACIÓN DE SERVIDORES
// Creamos una lista única de todas las bases de datos posibles para buscar fácil
const masterDbList = [];
[servers.ARG_BLOCK, servers.COL_BLOCK].forEach(block => {
  block.db_info.forEach(info => {
    masterDbList.push({
      ...info,
      server_host: block.server,
      port: block.port,
      user: block.user,
      password: block.password
    });
  });
});

// 5. CRUCE DE DATOS (RECONCILIACIÓN)
const finalTasks = [];

missingTasks.forEach(task => {
  const row = task.json.estado;

  // Buscar la query técnica en el input (Data Table)
  const queryData = allQueries.find(q => q.json.queryId === row.Query_ID);

  // Buscar la credencial técnica según País y Entorno que vienen del Sheets
  // Asumimos que en el Sheets el país viene como 'AR', 'CO', etc. y el entorno como 'APP', 'APP2'
  const dbConfig = masterDbList.find(d => 
    d.country === row.Pais && 
    d.entorno === row.Entorno
  );

  // Si encontramos tanto la query como el servidor, armamos el objeto de ejecución
  if (queryData && dbConfig) {
    finalTasks.push({
      json: {
        // Datos de control
        task_id: row.ID, // ID de la fila en el Sheets para marcar como completado luego
        query_id: row.Query_ID,
        tipo_ejecucion: executionType,

        // Datos de conexión
        server_host: dbConfig.server_host,
        server_port: dbConfig.port,
        db_user: dbConfig.user,
        db_pass: dbConfig.password,
        database_name: dbConfig.db,

        // Datos del entorno para el reporte
        entorno: dbConfig.entorno,
        pais: dbConfig.country,
        teams_channel: dbConfig.channelId,

        // SQL técnico
        sql_revision: queryData.json.revisionQuery,
        sql_correccion: queryData.json.correctionQuery
      }
    });
  }
});

return finalTasks;

